"""---
## 📉 Stage 10 — Loss Computation (Focal Loss)
> **Verifies:** The custom `FocalLoss` class from **Cell 24** of the original notebook  
> computes a valid scalar loss from the batch logits and labels.
"""

from sklearn.utils.class_weight import compute_class_weight

# ── FocalLoss definition (copied verbatim from original notebook Cell 24) ─
class FocalLoss(torch.nn.Module):
    def __init__(self, alpha=None, gamma=2.0, reduction='mean'):
        super().__init__()
        self.alpha     = alpha
        self.gamma     = gamma
        self.reduction = reduction

    def forward(self, logits, labels):
        ce_loss      = torch.nn.functional.cross_entropy(
            logits, labels, weight=self.alpha, reduction='none')
        pt           = torch.exp(-ce_loss)
        focal_weight = (1 - pt) ** self.gamma
        loss         = focal_weight * ce_loss
        return loss.mean() if self.reduction == 'mean' else loss.sum()

# ── Compute class weights from demo training labels ───────────────────────
train_labels_np = train_df['label'].values
unique_classes = np.unique(train_labels_np)
class_weights   = compute_class_weight(
    class_weight='balanced',
    classes=unique_classes,
    y=train_labels_np
)

# ── Use Optuna-tuned gamma from best_hp.json ──────────────────────────────
BEST_GAMMA        = 1.6919871410013687
BEST_FRAUD_WEIGHT = 2.8251219104371517

class_to_weight = dict(zip(unique_classes, class_weights))
alpha = torch.tensor([
    class_to_weight.get(0, 1.0),
    BEST_FRAUD_WEIGHT
], dtype=torch.float).to(DEVICE)
focal_loss_fn     = FocalLoss(alpha=alpha, gamma=BEST_GAMMA)

print(f'Class weights  → Legitimate: {class_weights[0]:.3f} | Fraudulent: {BEST_FRAUD_WEIGHT:.3f}')
print(f'Focal Loss γ   = {BEST_GAMMA:.4f}')

# ── Compute loss on the batch ─────────────────────────────────────────────
with torch.no_grad():
    outputs = model(input_ids=input_ids, attention_mask=attention_mask)
    loss_value = focal_loss_fn(outputs.logits, labels)
    

print(f'\nFocal Loss on batch: {loss_value.item():.6f}')

# ── Sanity checks ─────────────────────────────────────────────────────────
assert loss_value.item() > 0,        'Loss must be positive'
assert not torch.isnan(loss_value),  'Loss is NaN — check inputs'
assert not torch.isinf(loss_value),  'Loss is Inf — check inputs'
assert loss_value.shape == torch.Size([]),  'Loss must be a scalar'

print('\n✅ Stage 10 PASSED — Focal Loss computes valid scalar loss')

"""---
## 📊 Stage 11 — Metric Computation
> **Verifies:** All evaluation metrics (F1, ROC-AUC, MCC) can be computed from the model outputs.  
> Uses predictions from trained weights — metrics will be near-random (expected).  
> This confirms the metric pipeline is functional, not that the model is accurate.
"""

from sklearn.metrics import (
    f1_score, roc_auc_score, matthews_corrcoef,
    precision_score, recall_score, classification_report
)

# ── Get predictions for the entire test split ─────────────────────────────
all_probs  = []
all_labels = []

test_loader = DataLoader(test_ds, batch_size=BATCH_SIZE, shuffle=False)

with torch.no_grad():
    for test_batch in test_loader:
        ids  = test_batch['input_ids'].to(DEVICE)
        mask = test_batch['attention_mask'].to(DEVICE)
        lbl  = test_batch['labels'].to(DEVICE)

        out       = model(input_ids=ids, attention_mask=mask)
        probs_b   = torch.softmax(out.logits, dim=-1)[:, 1].cpu().numpy()
        all_probs.extend(probs_b.tolist())
        all_labels.extend(lbl.cpu().numpy().tolist())

all_probs  = np.array(all_probs)
all_labels = np.array(all_labels)

# ── Apply decision threshold ──────────────────────────────────────────────
EVAL_THRESHOLD = THRESHOLD  if WEIGHTS_LOADED else 0.5  # calibrated threshold from full training

preds     = (all_probs >= EVAL_THRESHOLD).astype(int)

print(f'Test set size    : {len(all_labels)}')
print(f'True fraud count : {all_labels.sum()}')
print(f'Predicted fraud  : {preds.sum()}  (at threshold={THRESHOLD})')

# ── Metrics ───────────────────────────────────────────────────────────────
# NOTE: With random weights these will be near-random — that is expected.
# The purpose is to verify the metric pipeline runs without error.
try:
    f1    = f1_score(all_labels,  preds,      pos_label=1, zero_division=0)
    rec   = recall_score(all_labels,  preds,  pos_label=1, zero_division=0)
    prec  = precision_score(all_labels, preds, pos_label=1, zero_division=0)
    if len(np.unique(all_labels)) > 1:
        auc = roc_auc_score(all_labels, all_probs)
    else:
        auc = float('nan')    
    mcc   = matthews_corrcoef(all_labels, preds)

    print(f'\n── Metrics on test subset ) ──')
    print(f'  F1  (fraud)    : {f1:.4f}   [target ≥ 0.91 after full training]')
    print(f'  Recall (fraud) : {rec:.4f}  [target ≥ 0.89 after full training]')
    print(f'  Precision      : {prec:.4f}  [target ≥ 0.93 after full training]')
    print(f'  ROC-AUC        : {auc:.4f}   [target ≥ 0.95 after full training]')
    print(f'  MCC            : {mcc:.4f}')
    print(f'\n  ⚠️  Metrics above are from subset of the data and are expected to be different from the fully tuned model.')
    print(f'      After full fine-tuning: F1≥0.91, Recall≥0.89, Precision≥0.93, AUC≥0.983')
    metrics_ok = True
except Exception as e:
    print(f'Metric computation error: {e}')
    metrics_ok = False

assert metrics_ok, 'Metric computation failed!'
print('\n✅ Stage 11 PASSED — all evaluation metrics compute without error')

"""---
## 🔮 Stage 12 — Inference Helper (`predict_fraud`)
> **Verifies:** The `predict_fraud()` inference helper from **Cell 65** of the original notebook  
> processes a single raw job posting dict and returns a well-formed prediction result.
"""

# ── predict_fraud — copied from original notebook Cell 65 ─────────────────
def predict_fraud(job_posting: dict, mdl, tok, threshold: float = 0.87) -> dict:
    """
    Predict fraud probability for a single job posting.
    job_posting: dict with keys matching TEXT_COLS + STRUCT_COLS
    Returns: {'fraud_probability': float, 'prediction': str, 'threshold_used': float}
    """
    text   = build_input_text({
                k: job_posting.get(k, "") for k in TEXT_COLS + STRUCT_COLS
            })
    inputs = tok(
        text, 
        return_tensors='pt',
        truncation=True, 
        max_length=MAX_SEQ_LEN,
        padding='max_length'
    )
    inputs = {k: v.to(DEVICE) for k, v in inputs.items()}
    mdl.eval()
    with torch.no_grad():
        logits_inf = mdl(**inputs).logits
    prob_fraud = torch.softmax(logits_inf, dim=-1)[0, 1].item()
    label_str  = 'FRAUDULENT' if prob_fraud >= threshold else 'LEGITIMATE'
    return {
        'fraud_probability': round(prob_fraud, 4),
        'prediction'       : label_str,
        'threshold_used'   : threshold,
    }
